function e(e,t){let n=new Set;if(t<=0)return n;if(Array.isArray(e)){for(let r of e){let e=Math.round(r);e>=1&&e<=t&&n.add(e)}return n}if(typeof e!=`string`||e.trim()===``)return n;let r=e.split(`,`);for(let e of r){let r=e.trim();if(!r)continue;let i=r.match(/^(\d+)\s*-\s*(\d+)$/);if(i){let e=Math.max(1,parseInt(i[1],10)),r=Math.min(t,parseInt(i[2],10));for(let t=e;t<=r;t++)n.add(t)}else{let e=parseInt(r,10);!isNaN(e)&&e>=1&&e<=t&&n.add(e)}}return n}export{e as t};